var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연, 오지만디아스.","JPN":"さすがはオジマンディアス。","ENG":"As expected, Ozymandias.","TWN":"果然，奧茲曼迪亞斯。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 무대에서 제가 마주한 상대 중에는 가장 방어가 견고하군요.","JPN":"この舞台で私が出会ったどの相手よりも防御が堅いです。","ENG":"Your defense is the strongest I've faced on this performance.","TWN":"在這個舞台上，我遇到的對手中，你的防禦最為堅固。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"순식간에 지면을 내려쳐서……?","JPN":"一瞬で地面を叩きつけて……？","ENG":"She suddenly hit the ground...?","TWN":"一瞬間震碎地面……？"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"설마, 이건……?","JPN":"まさか、これって……？","ENG":"Is this...?","TWN":"難道是……？"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"ええ。","ENG":"It is.","TWN":"沒錯。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 날 경기를 통해 당신 약점은 이미 만천하에 공개되어 있답니다.","JPN":"あの日の試合を通じて、あなたの弱点はすでに剥き出しも同然となりました。","ENG":"Your weakness was revealed to the world through that game.","TWN":"那天的比賽已經把你的弱點暴露無遺了。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"두 다리가 지면에 닿아 있지 않으면, 그 빈틈없는 방어에도 구멍이 생기죠.","JPN":"両足が地面についていなければ、あの抜かりない防御にも隙が生じる。","ENG":"If both your legs aren't on the ground, even your defense can't hold.","TWN":"如果雙腳不著地，即使是無懈可擊的防禦也會出現破綻。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하! 정말이지! 아무래도 앝보인 모양이네!","JPN":"は！　まったく！　どうやらなめられちゃったようね！","ENG":"Ha! You've got to be kidding me! Seems like I'm being underestimated!","TWN":"哈！真是的！看來是被小瞧了啊！"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"미안하지만, 이건 건틀렛이 아니라고? 이것저것 사정 봐줄 필요는 없겠지?","JPN":"悪いけど、これはガントレットじゃないのよ？　容赦する必要なんてないわよね？","ENG":"Sorry to burst your bubble, but this isn't the Gauntlet. So, I don't need to hold back.","TWN":"抱歉，這可不是聖鎧吧？沒必要顧慮那麼多吧？"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그럼, 진심으로 간다……!!","JPN":"だから、本気で行くわ……！！","ENG":"All right! Let's do this...!!","TWN":"那麼，要來了……！！"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상대로.","JPN":"予想どおり。","ENG":"As expected.","TWN":"果然不出所料。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무구를 개방할 생각이로군요.","JPN":"武具を開放するつもりですね。","ENG":"You are about to unleash your Armament.","TWN":"你打算開放武具了。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……えっ？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"처음부터 전력을 다하지 않은 건, 아마도 상대를 가늠하며 승부를 즐겨볼 셈이었겠죠.","JPN":"最初から本気を出していなかったのは、おそらく相手を見極めながら勝負を楽しむつもりだったのでしょう。","ENG":"The reason you didn't give your best from the beginning was because you wanted to gauge your opponent and enjoy the fight.","TWN":"一開始沒有全力以赴，大概是想在衡量對手的同時享受比賽吧。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신 말대로 이건 건틀렛이 아니에요.","JPN":"ですが、あなたの言ったとおり、これはガントレットではありません。","ENG":"But like you said, this isn't the Gauntlet.","TWN":"但正如你所說的，這不是聖鎧。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니까 싸움을 단순히 승부 감각으로 임하는 당신의 패배입니다.","JPN":"命がけの戦いに、遊び感覚で臨んでしまったあなたの負けです。","ENG":"So, your simply approaching this fight with a sense of victory is the reason you will lose.","TWN":"所以，單純地以勝負欲對待戰鬥，這便是你的敗因。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그건……? 내 검을……?","JPN":"それは……？　私の剣……？","ENG":"Is this... my sword…?","TWN":"那個是……？我的劍……？"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"특이한 검이지만, 사용법은 충분할 정도로 관람했어요.","JPN":"変わった剣ですが、使い方なら十分見させてもらいました。","ENG":"An unusual sword, but I have seen enough to know how to use it.","TWN":"雖然是把奇特的劍，但我已經看夠了它的用法。"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_2"},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면……!","JPN":"ならば……！","ENG":"Then...!","TWN":"這樣的話……！"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"크윽, 으으윽……!","JPN":"うっ、うううっ……！","ENG":"Urgh! Ngh...!","TWN":"咳，呃呃呃……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"무대 뒤에서 제 얼굴을 본 자는 살려두지 않는 게 원칙이지만.","JPN":"舞台裏で私の顔を見た者を生かしておくのは原則に反しますが、","ENG":"It's my principle to not spare anyone who has seen me behind the stage, but.","TWN":"看到我舞台後真面目的人都必須消失，這是我的原則。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"당신은 절 재미있게 했으니, 특별히 변덕을 부려드리죠.","JPN":"あなたは私を楽しませてくれたので、特別に見逃して差し上げましょう。","ENG":"Since you've entertained me, I'll let you live on a whim.","TWN":"不過你讓我覺得有趣，所以我特別破例一次。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"어차피 본 무대가 곧 시작될 예정이니까.","JPN":"もうすぐ本番が始まりますから。","ENG":"The main performance will soon start, anyway.","TWN":"反正正式的演出馬上就要開始了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 마지막…….","JPN":"これで最後……","ENG":"This will be the last one...","TWN":"這便是最後一個了……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 대균열에 클리파 차원으로 통하는 거울 조각을 끼워 넣었어.","JPN":"すべての大亀裂にクリファ次元に通じる鏡の破片を仕込んだ。","ENG":"I have placed a mirror fragment in all the Grand Dimension Crevices that connect to the Qlipha Dimension.","TWN":"我已經在所有的大峽谷中嵌入了通往逆卡巴拉次元的鏡片。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이제 이 대균열을 통하여, 그림자 전당 좌표에 있는 방주의 봉인을 여는 일만 남았군.","JPN":"あとはこの大亀裂を通じて、影の殿堂の座標にある箱舟の封印を解くだけ。","ENG":"Now, through it, it won't be long before I remove the Ark's Seal in the Shadow Palace coordinates.","TWN":"現在只剩下通過這個大峽谷，打開位於暗影殿堂的方舟封印了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래, 여기까지 온 건가…….","JPN":"やっと、ここまで来たのね……","ENG":"Yes, I have come this far...","TWN":"是啊，都已經到這一步了嗎……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거울을 사용하여 공간 도약하는 건, 그다지 내키지 않지만.","JPN":"鏡を使って空間跳躍するのは、あまり気が乗らないけど、","ENG":"I don't really like using the mirror to space jump, but…","TWN":"雖然不太願意用鏡子進行空間跳躍。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어쩔 수 없겠지. 함선 같은 사치를 부릴 때가 아니니까.","JPN":"仕方ないね。艦船のような贅沢もできない状況だから。","ENG":"Now is not the time to indulge in luxuries like dimensional ships.","TWN":"嗯……沒辦法了。現在還不是能奢侈地使用艦船的時候。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"이곳은 거울 속 파노라마의 세계. 지금은 잊혀져 버린 세계의 편린.","JPN":"ここは鏡の中、パノラマの世界。今は忘れられた世界の片鱗。","ENG":"This is Panorama's world within the mirror. A part of a now-forgotten world.","TWN":"這裡是鏡中的全景的世界。如今已被遺忘的世界的一小部分碎片。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"마왕의 권능으로 재조립된 파노라마의 세계는 시간과 공간마저 단절되어버린 유배지.","JPN":"魔王の権能で組み直されたパノラマの世界は、時間と空間さえ断絶された流刑地。","ENG":"Panorama's world is a place of exile, reassembled by the Demon Lord's power, and cut off from time and space.","TWN":"被魔王的權能重新組裝，是時間和空間都被切斷的流放地。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"이곳에서 나는 목적지를 향해 길을 걷는다.","JPN":"ここで私は目的地へと足を運ぶ。","ENG":"Here, I walk the path to my destination.","TWN":"在這裡，我朝著目的地前行。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"목적지는 눈이 그치지 않는 무덤.","JPN":"目的地は雪が止まない墓。","ENG":"The grave of endless snow.","TWN":"那裡有雪永不停息的墳墓。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"기억 속 그림자 전당을 향해, 나는 하염없이 길을 헤맨다.","JPN":"記憶の中にある影の殿堂に向かって、私は限りなく道に迷う。","ENG":"I wander aimlessly toward the Shadow Palace within my memories.","TWN":"朝著記憶中的暗影殿堂，我茫然地徘徊在路上。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 이내 마주하게 되는 이 세계의 법칙.","JPN":"そして、そのうち立ち向かうことになるこの世界の法則。","ENG":"And soon, encounter this world's law.","TWN":"很快，我就將面對這個世界的法則。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"자신과 완전히 똑같은 거울상과 충돌하게 되는 것.","JPN":"完全に自分と同じ姿をした鏡像と衝突すること。","ENG":"Facing against a mirror image of yourself.","TWN":"遇到那個完全與自己相同的鏡像。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"거울의 주인이라고 할 지라도, 그 예외는 없겠지.","JPN":"鏡の持ち主であっても、例外ではないはず。","ENG":"Not even the mirror's owner is an exception.","TWN":"即使是鏡子的主人，也不會例外。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"이게 정말 옳은 거라고 생각해?","JPN":"本当にこれが正しいことだと思う？","ENG":"Do you really think this is the right thing to do?","TWN":"你覺得這真的是正確的嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"실은 너도 알고 있잖아, 스완.","JPN":"ねえ、あなたもわかっているんじゃない？　スワン。","ENG":"You already know the answer, Swan.","TWN":"其實你也知道的，史旺。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그 남자</color>는 누구보다도 공공의 이익을 우선시하는 사람이었어.","JPN":"<color=#ffd34c>あの男</color>は誰よりも公共の利益を優先させる人だった。","ENG":"<color=#ffd34c>The man</color> is someone who will put the public interest above all else.","TWN":"<color=#ffd34c>那個人</color>是一個比任何人都更優先考慮公共利益的人。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"그걸 위해서 자기 목숨을 내던질 정도로 말이야.","JPN":"そのために自分の命を投げ出すほどにね。","ENG":"Enough so that he'll give up his life for it.","TWN":"甚至願意為此捨棄自己的生命。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"네가 이런 일을 벌이는 걸, 그 남자가 좋아할 리 없잖아.","JPN":"あなたがこんなことをしていたら、あの男が喜ぶわけないでしょう？","ENG":"What you are doing here, the man will not like it.","TWN":"你做這種事，那個人不會喜歡的。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 이건 그 남자와 관계없어요.","JPN":"いいえ。これはあの男とは関係ありません。","ENG":"No. This has nothing to do with the man.","TWN":"不。這和那個人無關。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하는 거예요. 이게 제 바람이고, 제 선택이에요.","JPN":"私が欲しているのです。これが私の望みで、私の選択です。","ENG":"This is what I want. This is my wish and my choice.","TWN":"這是我想要的。這是我的願望，也是我的選擇。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오래전부터 그것을 이루기 위해서라면, 어떤 악역이든 받아들이겠다고 다짐했으니까.","JPN":"それを叶えるためなら、どんな悪役でも喜んで引き受けると決めたのですから。","ENG":"I promised to myself a long time ago that I would take on any villainous role to achieve this.","TWN":"很久以前我就下定決心，為了實現那個目標，不管是什麼樣的反派角色我都願意接受。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알고 있잖아요.","JPN":"あなたもわかっているでしょう？","ENG":"You know that just as well as I do.","TWN":"你也知道的吧。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것을 되돌리기 위해서는 <color=#ffd34c>천사</color>의 힘이 필요하다는 걸.","JPN":"すべてを取り返すためには<color=#ffd34c>天使</color>の力が必要だってことを。","ENG":"In order to revert everything back, I need the power of an <color=#ffd34c>angel</color>.","TWN":"要恢復一切，需要<color=#ffd34c>天使</color>的力量。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그걸 위해서는 <color=#ffd34c>그녀</color>가 자기 스스로와 마주할 필요가 있어요.","JPN":"そのためには<color=#ffd34c>彼女</color>が自分自身と向き合う必要があるのです。","ENG":"For that, <color=#ffd34c>she</color> will need to face herself.","TWN":"為此，<color=#ffd34c>她</color>需要面對自己。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 결국 천사는 나타나지 않았어.","JPN":"でも結局天使は現われなかった。","ENG":"But the angel never appeared.","TWN":"但最終天使並沒有出現。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"우리 세계에 강림했던 그건, 천사 같은 게 아니었어.","JPN":"私たちの世界に降臨したアレは、天使なんかじゃなかった。","ENG":"What descended to our world wasn't an angel.","TWN":"降臨我們世界的那個東西，並不是天使。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 황금 새벽회는 결국 천사를 불러내는 데 실패하고 말았죠.","JPN":"そのとおりです。黄金の暁団は結局天使を呼び出すことに失敗してしまいました。","ENG":"You're right. The Golden Dawn ultimately failed to summon an angel.","TWN":"沒錯。黃金黎明會最終沒能召喚出天使。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다고 당신처럼 하염없이 주저앉아 있을 수만은 없어요.","JPN":"だからといって、あなたのようにずっと落ち込んでいるわけにはいきません。","ENG":"But that doesn't mean that I should sit on my hands and do nothing like you.","TWN":"那也不能像你一樣呆若木雞地癱坐在地上。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ADLER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ADLER_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 제 눈앞에서 이만 꺼져주세요.","JPN":"だから、私の目の前から消えてください。","ENG":"Now, please get out of my sight.","TWN":"所以，請從我眼前消失吧。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무력했던, 무명 시절의 나.","JPN":"無力だった、無名時代の私。","ENG":"The helpless and unknown me.","TWN":"曾經無力的、無名的我。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"서막이 오르고, 극의 주연들이 단서를 좇기 시작했습니다.","JPN":"序幕が始まり、劇の主演たちが手がかりを追い始めました。","ENG":"As the opening scene unfolds, the lead characters of the play start following the clues.","TWN":"大幕已經拉開，劇中的演員們開始尋找線索了。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_13"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"작고 사소했던 사건들은 들불처럼 겉잡을 수 없이 커지고, 누가 이 모든 것을 촉발한 악역인지 사람들은 곧 알게 될 겁니다.","JPN":"小さく些細だった事件は野火のように手がつけられないほど燃え上がり、火付け役の悪人は誰なのか、皆が知ることになるでしょう。","ENG":"Minor, trivial incidents spread like wildfire, and the audience will soon figure out the true villain that triggered this entire narrative.","TWN":"一個微不足道的事件會像野火一樣一發不可收拾，人們很快就會意識到究竟誰才是始作俑者。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_14"},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 모든 준비는 끝났어요, 암군이여.","JPN":"これですべての準備が整いました、暗君よ。","ENG":"All the preparations are complete, Ignorant Monarch.","TWN":"這樣一來，一切都準備緒了，昏君。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_15"},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이라는 시련이 그녀가 선택한 세계를 무너뜨릴 때.","JPN":"あなたという試練が、彼女の選んだ世界を崩す時……","ENG":"When the trial that is yourself brings ruin to the world she chose.","TWN":"當你作為她的試煉，毀掉她所選擇的世界時……"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_16"},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비로소 그녀도… 자기자신이 누구인지 깨닫게 되겠죠.","JPN":"彼女もようやく……自身の正体を知ることになるでしょう。","ENG":"That is when she... will realize who she is.","TWN":"她即會明白……自己究竟是誰。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_17"}]`);export{e as default};